"""Zone listing."""

from shipkit._internal import normalize_zone

_ZONES = ("local", "regional", "national")
_KNOWN_ZONES = frozenset(_ZONES)


def list_service_zones() -> list[str]:
    return list(_ZONES)


def _zone_index(zone: str) -> int:
    normalized = normalize_zone(zone, known=_KNOWN_ZONES)
    return _ZONES.index(normalized)
